const items = $input.all();
const item = items[0].json;
const isTelegram = item.message !== undefined;
let platform, userId, chatId, text, name, photo;

if (isTelegram) {
  platform = 'telegram';
  userId = String(item.message.from.id);
  chatId = item.message.chat.id;
  text = item.message.text || item.message.caption || '';
  name = item.message.from.first_name + ' ' + (item.message.from.last_name || '');
  photo = item.message.photo ? item.message.photo[item.message.photo.length - 1].file_id : null;
} else {
  platform = 'whatsapp';
  userId = item.From;
  chatId = item.From;
  text = item.Body || '';
  name = item.ProfileName || 'Cliente';
  photo = null;
}

const sessionId = platform + '_' + userId;
return [{
  json: {
    platform,
    userId,
    chatId,
    text: text.trim(),
    name: name.trim(),
    photo,
    sessionId
  }
}];

// Guardar conversación en Supabase
const input = $input.first().json;
const aiResult = $input.all()[1].json;

const historyData = {
  session_id: input.sessionId,
  platform: input.platform,
  user_id: input.userId,
  messages: [
    { role: 'user', content: input.text, timestamp: new Date().toISOString() },
    { role: 'assistant', content: aiResult?.content || 'OK', timestamp: new Date().toISOString() }
  ],
  updated_at: new Date().toISOString()
};

return [{ json: historyData }];

// Preparar respuesta según plataforma
const input = $input.first().json;
const aiResult = $input.all()[1].json;
const content = aiResult?.content || 'Hola! Soy el asistente de Kyros. ¿En qué puedo ayudarte?';

// Intentar parsear JSON de la IA
let parsedResponse;
try {
  parsedResponse = JSON.parse(content);
} catch (e) {
  parsedResponse = { respuesta: content };
}

const message = parsedResponse.respuesta || content;
let output;

if (input.platform === 'telegram') {
  output = {
    chat_id: input.chatId,
    text: message,
    parse_mode: 'Markdown'
  };
} else {
  output = {
    To: input.chatId,
    Body: message
  };
}

return [{
  json: {
    output,
    platform: input.platform,
    chatId: input.chatId
  }
}];
